args.query:
SELECT pbe.Id as PricebookEntryId, pbe.UnitPrice as CatalogUnitPrice, pbe.Product2Id, p2.Name as ProductName
FROM PricebookEntry pbe
JOIN Product2 p2 ON p2.Id = pbe.Product2Id;

